import { useI18n } from "@/lib/i18n";
import { useQuery, useMutation } from "@tanstack/react-query";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Skeleton } from "@/components/ui/skeleton";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from "@/components/ui/dialog";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Plus,
  BookOpen,
  Video,
  ClipboardCheck,
  ArrowLeft,
  ArrowRight,
  Eye,
  EyeOff,
  GraduationCap,
  FileText,
  HelpCircle,
  Trash2,
} from "lucide-react";
import { useState } from "react";
import type {
  Course,
  CourseLesson,
  CourseQuiz,
  QuizQuestion,
  ProjectSubmission,
} from "@shared/schema";
import { isUnauthorizedError } from "@/lib/auth-utils";

interface QuizWithQuestions extends CourseQuiz {
  questions?: QuizQuestion[];
}

export default function TrainerDashboard() {
  const { t, lang, isRtl } = useI18n();
  const { toast } = useToast();

  const [selectedCourse, setSelectedCourse] = useState<Course | null>(null);
  const [courseDialogOpen, setCourseDialogOpen] = useState(false);
  const [lessonDialogOpen, setLessonDialogOpen] = useState(false);
  const [quizDialogOpen, setQuizDialogOpen] = useState(false);
  const [questionDialogOpen, setQuestionDialogOpen] = useState(false);
  const [gradeDialogOpen, setGradeDialogOpen] = useState(false);
  const [selectedQuiz, setSelectedQuiz] = useState<CourseQuiz | null>(null);
  const [selectedProject, setSelectedProject] = useState<ProjectSubmission | null>(null);

  const [courseForm, setCourseForm] = useState({
    titleAr: "",
    titleEn: "",
    descriptionAr: "",
    descriptionEn: "",
    category: "",
    duration: 0,
  });

  const [lessonForm, setLessonForm] = useState({
    titleAr: "",
    titleEn: "",
    videoUrl: "",
    contentAr: "",
    contentEn: "",
    orderIndex: 0,
    durationMinutes: 0,
  });

  const [quizForm, setQuizForm] = useState({
    titleAr: "",
    titleEn: "",
    type: "intermediate" as "intermediate" | "final",
    passingScore: 60,
  });

  const [questionForm, setQuestionForm] = useState({
    questionAr: "",
    questionEn: "",
    options: [
      { textAr: "", textEn: "" },
      { textAr: "", textEn: "" },
      { textAr: "", textEn: "" },
      { textAr: "", textEn: "" },
    ],
    correctAnswer: 0,
  });

  const [gradeForm, setGradeForm] = useState({ grade: 0, feedback: "" });

  const { data: courses, isLoading } = useQuery<Course[]>({
    queryKey: ["/api/courses/all"],
  });

  const { data: lessons } = useQuery<CourseLesson[]>({
    queryKey: ["/api/courses", selectedCourse?.id, "lessons"],
    enabled: !!selectedCourse,
  });

  const { data: quizzes } = useQuery<QuizWithQuestions[]>({
    queryKey: ["/api/courses", selectedCourse?.id, "quizzes"],
    enabled: !!selectedCourse,
  });

  const { data: projects } = useQuery<ProjectSubmission[]>({
    queryKey: ["/api/courses", selectedCourse?.id, "projects"],
    enabled: !!selectedCourse,
  });

  function handleAuthError(error: Error) {
    if (isUnauthorizedError(error)) {
      toast({ title: "Unauthorized", description: "Logging in again...", variant: "destructive" });
      setTimeout(() => { window.location.href = "/auth"; }, 500);
      return true;
    }
    return false;
  }

  const createCourseMutation = useMutation({
    mutationFn: async (data: typeof courseForm) => {
      const res = await apiRequest("POST", "/api/courses", data);
      return res.json();
    },
    onSuccess: () => {
      toast({ title: t("common.success") });
      queryClient.invalidateQueries({ queryKey: ["/api/courses/all"] });
      setCourseDialogOpen(false);
      setCourseForm({ titleAr: "", titleEn: "", descriptionAr: "", descriptionEn: "", category: "", duration: 0 });
    },
    onError: (error: Error) => {
      if (!handleAuthError(error)) {
        toast({ title: t("common.error"), description: error.message, variant: "destructive" });
      }
    },
  });

  const togglePublishMutation = useMutation({
    mutationFn: async ({ id, isPublished }: { id: string; isPublished: boolean }) => {
      const res = await apiRequest("PATCH", `/api/courses/${id}`, { isPublished });
      return res.json();
    },
    onSuccess: () => {
      toast({ title: t("common.success") });
      queryClient.invalidateQueries({ queryKey: ["/api/courses/all"] });
    },
    onError: (error: Error) => {
      if (!handleAuthError(error)) {
        toast({ title: t("common.error"), description: error.message, variant: "destructive" });
      }
    },
  });

  const addLessonMutation = useMutation({
    mutationFn: async (data: typeof lessonForm) => {
      const res = await apiRequest("POST", `/api/courses/${selectedCourse!.id}/lessons`, data);
      return res.json();
    },
    onSuccess: () => {
      toast({ title: t("common.success") });
      queryClient.invalidateQueries({ queryKey: ["/api/courses", selectedCourse?.id, "lessons"] });
      setLessonDialogOpen(false);
      setLessonForm({ titleAr: "", titleEn: "", videoUrl: "", contentAr: "", contentEn: "", orderIndex: 0, durationMinutes: 0 });
    },
    onError: (error: Error) => {
      if (!handleAuthError(error)) {
        toast({ title: t("common.error"), description: error.message, variant: "destructive" });
      }
    },
  });

  const deleteLessonMutation = useMutation({
    mutationFn: async (lessonId: string) => {
      const res = await apiRequest("DELETE", `/api/lessons/${lessonId}`);
      return res.json();
    },
    onSuccess: () => {
      toast({ title: lang === "ar" ? "تم حذف الدرس" : "Lesson deleted" });
      queryClient.invalidateQueries({ queryKey: ["/api/courses", selectedCourse?.id, "lessons"] });
    },
    onError: (error: Error) => {
      if (!handleAuthError(error)) {
        toast({ title: t("common.error"), description: error.message, variant: "destructive" });
      }
    },
  });

  const deleteCourseMutation = useMutation({
    mutationFn: async (courseId: string) => {
      const res = await apiRequest("DELETE", `/api/courses/${courseId}`);
      return res.json();
    },
    onSuccess: () => {
      toast({ title: lang === "ar" ? "تم حذف الدورة" : "Course deleted" });
      queryClient.invalidateQueries({ queryKey: ["/api/courses/all"] });
      setSelectedCourse(null);
    },
    onError: (error: Error) => {
      if (!handleAuthError(error)) {
        toast({ title: t("common.error"), description: error.message, variant: "destructive" });
      }
    },
  });

  const addQuizMutation = useMutation({
    mutationFn: async (data: typeof quizForm) => {
      const res = await apiRequest("POST", `/api/courses/${selectedCourse!.id}/quizzes`, data);
      return res.json();
    },
    onSuccess: () => {
      toast({ title: t("common.success") });
      queryClient.invalidateQueries({ queryKey: ["/api/courses", selectedCourse?.id, "quizzes"] });
      setQuizDialogOpen(false);
      setQuizForm({ titleAr: "", titleEn: "", type: "intermediate", passingScore: 60 });
    },
    onError: (error: Error) => {
      if (!handleAuthError(error)) {
        toast({ title: t("common.error"), description: error.message, variant: "destructive" });
      }
    },
  });

  const addQuestionMutation = useMutation({
    mutationFn: async (data: typeof questionForm) => {
      const res = await apiRequest("POST", `/api/quizzes/${selectedQuiz!.id}/questions`, data);
      return res.json();
    },
    onSuccess: () => {
      toast({ title: t("common.success") });
      queryClient.invalidateQueries({ queryKey: ["/api/courses", selectedCourse?.id, "quizzes"] });
      setQuestionDialogOpen(false);
      setQuestionForm({
        questionAr: "", questionEn: "",
        options: [{ textAr: "", textEn: "" }, { textAr: "", textEn: "" }, { textAr: "", textEn: "" }, { textAr: "", textEn: "" }],
        correctAnswer: 0,
      });
    },
    onError: (error: Error) => {
      if (!handleAuthError(error)) {
        toast({ title: t("common.error"), description: error.message, variant: "destructive" });
      }
    },
  });

  const gradeProjectMutation = useMutation({
    mutationFn: async ({ id, grade, feedback }: { id: string; grade: number; feedback: string }) => {
      const res = await apiRequest("POST", `/api/projects/${id}/grade`, { grade, feedback });
      return res.json();
    },
    onSuccess: () => {
      toast({ title: t("common.success") });
      queryClient.invalidateQueries({ queryKey: ["/api/courses", selectedCourse?.id, "projects"] });
      setGradeDialogOpen(false);
      setGradeForm({ grade: 0, feedback: "" });
    },
    onError: (error: Error) => {
      if (!handleAuthError(error)) {
        toast({ title: t("common.error"), description: error.message, variant: "destructive" });
      }
    },
  });

  const BackArrow = isRtl ? ArrowRight : ArrowLeft;

  if (selectedCourse) {
    return (
      <div className="p-4 sm:p-6 space-y-6 max-w-5xl mx-auto">
        <div className="flex items-center gap-3 flex-wrap">
          <Button
            variant="ghost"
            size="icon"
            onClick={() => setSelectedCourse(null)}
            data-testid="button-back-to-courses"
          >
            <BackArrow className="h-4 w-4" />
          </Button>
          <div className="flex-1 min-w-0">
            <h1 className="text-2xl font-bold truncate">
              {lang === "ar" ? selectedCourse.titleAr : selectedCourse.titleEn || selectedCourse.titleAr}
            </h1>
          </div>
          <Button
            variant={selectedCourse.isPublished ? "outline" : "default"}
            size="sm"
            onClick={() =>
              togglePublishMutation.mutate({
                id: selectedCourse.id,
                isPublished: !selectedCourse.isPublished,
              })
            }
            disabled={togglePublishMutation.isPending}
            data-testid="button-toggle-publish"
          >
            {selectedCourse.isPublished ? (
              <>
                <EyeOff className="h-3.5 w-3.5" />
                <span className="ms-1.5">{t("common.unpublish")}</span>
              </>
            ) : (
              <>
                <Eye className="h-3.5 w-3.5" />
                <span className="ms-1.5">{t("common.publish")}</span>
              </>
            )}
          </Button>
        </div>

        <Tabs defaultValue="lessons">
          <TabsList data-testid="tabs-course-management">
            <TabsTrigger value="lessons" data-testid="tab-lessons">
              <Video className="h-3.5 w-3.5 me-1.5" />
              {t("courses.lessons")}
            </TabsTrigger>
            <TabsTrigger value="quizzes" data-testid="tab-quizzes">
              <HelpCircle className="h-3.5 w-3.5 me-1.5" />
              {t("courses.quizzes")}
            </TabsTrigger>
            <TabsTrigger value="projects" data-testid="tab-projects">
              <FileText className="h-3.5 w-3.5 me-1.5" />
              {t("courses.project")}
            </TabsTrigger>
          </TabsList>

          <TabsContent value="lessons" className="space-y-4 mt-4">
            <div className="flex items-center justify-between gap-2 flex-wrap">
              <h2 className="text-lg font-semibold">{t("trainer.manageLessons")}</h2>
              <Button
                size="sm"
                onClick={() => {
                  setLessonForm((prev) => ({
                    ...prev,
                    orderIndex: (lessons?.length || 0) + 1,
                  }));
                  setLessonDialogOpen(true);
                }}
                data-testid="button-add-lesson"
              >
                <Plus className="h-3.5 w-3.5" />
                <span className="ms-1.5">{t("courses.addLesson")}</span>
              </Button>
            </div>

            {lessons && lessons.length > 0 ? (
              <div className="space-y-3">
                {lessons
                  .sort((a, b) => a.orderIndex - b.orderIndex)
                  .map((lesson, idx) => (
                    <Card key={lesson.id} data-testid={`card-lesson-${lesson.id}`}>
                      <CardContent className="p-4">
                        <div className="flex items-start gap-3">
                          <div className="flex items-center justify-center h-8 w-8 rounded-md bg-primary/10 text-primary text-sm font-medium shrink-0">
                            {idx + 1}
                          </div>
                          <div className="flex-1 min-w-0 space-y-1">
                            <h3 className="font-medium text-sm">
                              {lang === "ar" ? lesson.titleAr : lesson.titleEn || lesson.titleAr}
                            </h3>
                            {lesson.videoUrl && (
                              <p className="text-xs text-muted-foreground flex items-center gap-1 truncate">
                                <Video className="h-3 w-3 shrink-0" />
                                {lesson.videoUrl}
                              </p>
                            )}
                            {lesson.durationMinutes ? (
                              <Badge variant="secondary" className="text-xs">
                                {lesson.durationMinutes} {t("courses.duration")}
                              </Badge>
                            ) : null}
                          </div>
                          <Button
                            size="sm"
                            variant="ghost"
                            className="text-destructive hover:text-destructive h-8 w-8 p-0 shrink-0"
                            data-testid={`button-delete-lesson-${lesson.id}`}
                            onClick={() => {
                              if (confirm(lang === "ar" ? "هل أنت متأكد من حذف هذا الدرس؟" : "Are you sure you want to delete this lesson?")) {
                                deleteLessonMutation.mutate(lesson.id);
                              }
                            }}
                          >
                            <Trash2 className="h-4 w-4" />
                          </Button>
                        </div>
                      </CardContent>
                    </Card>
                  ))}
              </div>
            ) : (
              <Card>
                <CardContent className="py-12 text-center">
                  <Video className="h-10 w-10 mx-auto mb-3 text-muted-foreground opacity-40" />
                  <p className="text-sm text-muted-foreground">{t("common.noData")}</p>
                </CardContent>
              </Card>
            )}
          </TabsContent>

          <TabsContent value="quizzes" className="space-y-4 mt-4">
            <div className="flex items-center justify-between gap-2 flex-wrap">
              <h2 className="text-lg font-semibold">{t("trainer.manageQuizzes")}</h2>
              <Button
                size="sm"
                onClick={() => setQuizDialogOpen(true)}
                data-testid="button-add-quiz"
              >
                <Plus className="h-3.5 w-3.5" />
                <span className="ms-1.5">{t("courses.addQuiz")}</span>
              </Button>
            </div>

            {quizzes && quizzes.length > 0 ? (
              <div className="space-y-3">
                {quizzes.map((quiz) => (
                  <Card key={quiz.id} data-testid={`card-quiz-${quiz.id}`}>
                    <CardContent className="p-4 space-y-3">
                      <div className="flex items-start justify-between gap-2 flex-wrap">
                        <div className="space-y-1">
                          <h3 className="font-medium text-sm">
                            {lang === "ar" ? quiz.titleAr : quiz.titleEn || quiz.titleAr}
                          </h3>
                          <div className="flex items-center gap-2 flex-wrap">
                            <Badge variant="secondary" className="text-xs">
                              {quiz.type === "final" ? t("quiz.final") : t("quiz.intermediate")}
                            </Badge>
                            <span className="text-xs text-muted-foreground">
                              {t("quiz.passingScore")}: {quiz.passingScore}%
                            </span>
                          </div>
                        </div>
                        <Button
                          size="sm"
                          variant="outline"
                          onClick={() => {
                            setSelectedQuiz(quiz);
                            setQuestionDialogOpen(true);
                          }}
                          data-testid={`button-add-question-${quiz.id}`}
                        >
                          <Plus className="h-3.5 w-3.5" />
                          <span className="ms-1.5">{t("quiz.addQuestion")}</span>
                        </Button>
                      </div>

                      {quiz.questions && quiz.questions.length > 0 && (
                        <div className="space-y-2 pt-2 border-t">
                          {quiz.questions.map((q, qIdx) => (
                            <div key={q.id} className="text-sm space-y-1" data-testid={`question-${q.id}`}>
                              <p className="font-medium text-xs">
                                {qIdx + 1}. {lang === "ar" ? q.questionAr : q.questionEn || q.questionAr}
                              </p>
                              <div className="grid grid-cols-2 gap-1 ps-4">
                                {(q.options as Array<{ textAr: string; textEn: string }>).map(
                                  (opt, optIdx) => (
                                    <span
                                      key={optIdx}
                                      className={`text-xs ${
                                        optIdx === q.correctAnswer
                                          ? "text-green-600 dark:text-green-400 font-medium"
                                          : "text-muted-foreground"
                                      }`}
                                    >
                                      {String.fromCharCode(65 + optIdx)}.{" "}
                                      {lang === "ar" ? opt.textAr : opt.textEn || opt.textAr}
                                    </span>
                                  )
                                )}
                              </div>
                            </div>
                          ))}
                        </div>
                      )}
                    </CardContent>
                  </Card>
                ))}
              </div>
            ) : (
              <Card>
                <CardContent className="py-12 text-center">
                  <HelpCircle className="h-10 w-10 mx-auto mb-3 text-muted-foreground opacity-40" />
                  <p className="text-sm text-muted-foreground">{t("common.noData")}</p>
                </CardContent>
              </Card>
            )}
          </TabsContent>

          <TabsContent value="projects" className="space-y-4 mt-4">
            <h2 className="text-lg font-semibold">{t("trainer.reviewProjects")}</h2>

            {projects && projects.length > 0 ? (
              <div className="space-y-3">
                {projects.map((project) => (
                  <Card key={project.id} data-testid={`card-project-${project.id}`}>
                    <CardContent className="p-4">
                      <div className="flex items-start justify-between gap-2 flex-wrap">
                        <div className="space-y-1 flex-1 min-w-0">
                          <h3 className="font-medium text-sm">
                            {lang === "ar" ? project.titleAr : project.titleEn || project.titleAr}
                          </h3>
                          <p className="text-xs text-muted-foreground line-clamp-2">
                            {lang === "ar"
                              ? project.descriptionAr
                              : project.descriptionEn || project.descriptionAr}
                          </p>
                          {project.fileUrl && (
                            <a
                              href={project.fileUrl}
                              target="_blank"
                              rel="noopener noreferrer"
                              className="text-xs text-primary underline"
                              data-testid={`link-project-file-${project.id}`}
                            >
                              {lang === "ar" ? "عرض الملف" : "View File"}
                            </a>
                          )}
                        </div>
                        <div className="flex items-center gap-2">
                          {project.grade !== null && project.grade !== undefined ? (
                            <Badge variant="default" data-testid={`badge-grade-${project.id}`}>
                              {project.grade}/100
                            </Badge>
                          ) : (
                            <Button
                              size="sm"
                              onClick={() => {
                                setSelectedProject(project);
                                setGradeForm({ grade: 0, feedback: "" });
                                setGradeDialogOpen(true);
                              }}
                              data-testid={`button-grade-project-${project.id}`}
                            >
                              <ClipboardCheck className="h-3.5 w-3.5" />
                              <span className="ms-1.5">{t("trainer.gradeProject")}</span>
                            </Button>
                          )}
                        </div>
                      </div>
                    </CardContent>
                  </Card>
                ))}
              </div>
            ) : (
              <Card>
                <CardContent className="py-12 text-center">
                  <FileText className="h-10 w-10 mx-auto mb-3 text-muted-foreground opacity-40" />
                  <p className="text-sm text-muted-foreground">{t("common.noData")}</p>
                </CardContent>
              </Card>
            )}
          </TabsContent>
        </Tabs>

        <Dialog open={lessonDialogOpen} onOpenChange={setLessonDialogOpen}>
          <DialogContent className="max-w-lg max-h-[90vh] overflow-y-auto">
            <DialogHeader>
              <DialogTitle>{t("courses.addLesson")}</DialogTitle>
            </DialogHeader>
            <div className="space-y-3">
              <Input
                placeholder={lang === "ar" ? "عنوان الدرس (عربي)" : "Lesson Title (Arabic)"}
                value={lessonForm.titleAr}
                onChange={(e) => setLessonForm((f) => ({ ...f, titleAr: e.target.value }))}
                data-testid="input-lesson-title-ar"
              />
              <Input
                placeholder={lang === "ar" ? "عنوان الدرس (إنجليزي)" : "Lesson Title (English)"}
                value={lessonForm.titleEn}
                onChange={(e) => setLessonForm((f) => ({ ...f, titleEn: e.target.value }))}
                data-testid="input-lesson-title-en"
              />
              <Input
                placeholder={t("courses.videoUrl")}
                value={lessonForm.videoUrl}
                onChange={(e) => setLessonForm((f) => ({ ...f, videoUrl: e.target.value }))}
                data-testid="input-lesson-video-url"
              />
              <Textarea
                placeholder={lang === "ar" ? "المحتوى (عربي)" : "Content (Arabic)"}
                value={lessonForm.contentAr}
                onChange={(e) => setLessonForm((f) => ({ ...f, contentAr: e.target.value }))}
                rows={3}
                data-testid="input-lesson-content-ar"
              />
              <Textarea
                placeholder={lang === "ar" ? "المحتوى (إنجليزي)" : "Content (English)"}
                value={lessonForm.contentEn}
                onChange={(e) => setLessonForm((f) => ({ ...f, contentEn: e.target.value }))}
                rows={3}
                data-testid="input-lesson-content-en"
              />
              <div className="grid grid-cols-2 gap-3">
                <Input
                  type="number"
                  placeholder={lang === "ar" ? "الترتيب" : "Order"}
                  value={lessonForm.orderIndex || ""}
                  onChange={(e) =>
                    setLessonForm((f) => ({ ...f, orderIndex: parseInt(e.target.value) || 0 }))
                  }
                  data-testid="input-lesson-order"
                />
                <Input
                  type="number"
                  placeholder={t("courses.duration")}
                  value={lessonForm.durationMinutes || ""}
                  onChange={(e) =>
                    setLessonForm((f) => ({ ...f, durationMinutes: parseInt(e.target.value) || 0 }))
                  }
                  data-testid="input-lesson-duration"
                />
              </div>
            </div>
            <DialogFooter>
              <Button variant="outline" onClick={() => setLessonDialogOpen(false)} data-testid="button-cancel-lesson">
                {t("common.cancel")}
              </Button>
              <Button
                onClick={() => addLessonMutation.mutate(lessonForm)}
                disabled={!lessonForm.titleAr || addLessonMutation.isPending}
                data-testid="button-save-lesson"
              >
                {t("common.save")}
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>

        <Dialog open={quizDialogOpen} onOpenChange={setQuizDialogOpen}>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>{t("courses.addQuiz")}</DialogTitle>
            </DialogHeader>
            <div className="space-y-3">
              <Input
                placeholder={lang === "ar" ? "عنوان الاختبار (عربي)" : "Quiz Title (Arabic)"}
                value={quizForm.titleAr}
                onChange={(e) => setQuizForm((f) => ({ ...f, titleAr: e.target.value }))}
                data-testid="input-quiz-title-ar"
              />
              <Input
                placeholder={lang === "ar" ? "عنوان الاختبار (إنجليزي)" : "Quiz Title (English)"}
                value={quizForm.titleEn}
                onChange={(e) => setQuizForm((f) => ({ ...f, titleEn: e.target.value }))}
                data-testid="input-quiz-title-en"
              />
              <Select
                value={quizForm.type}
                onValueChange={(val) => setQuizForm((f) => ({ ...f, type: val as "intermediate" | "final" }))}
              >
                <SelectTrigger data-testid="select-quiz-type">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="intermediate">{t("quiz.intermediate")}</SelectItem>
                  <SelectItem value="final">{t("quiz.final")}</SelectItem>
                </SelectContent>
              </Select>
              <Input
                type="number"
                placeholder={t("quiz.passingScore")}
                value={quizForm.passingScore || ""}
                onChange={(e) =>
                  setQuizForm((f) => ({ ...f, passingScore: parseInt(e.target.value) || 0 }))
                }
                data-testid="input-quiz-passing-score"
              />
            </div>
            <DialogFooter>
              <Button variant="outline" onClick={() => setQuizDialogOpen(false)} data-testid="button-cancel-quiz">
                {t("common.cancel")}
              </Button>
              <Button
                onClick={() => addQuizMutation.mutate(quizForm)}
                disabled={!quizForm.titleAr || addQuizMutation.isPending}
                data-testid="button-save-quiz"
              >
                {t("common.save")}
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>

        <Dialog open={questionDialogOpen} onOpenChange={setQuestionDialogOpen}>
          <DialogContent className="max-w-lg max-h-[90vh] overflow-y-auto">
            <DialogHeader>
              <DialogTitle>{t("quiz.addQuestion")}</DialogTitle>
            </DialogHeader>
            <div className="space-y-3">
              <Textarea
                placeholder={lang === "ar" ? "السؤال (عربي)" : "Question (Arabic)"}
                value={questionForm.questionAr}
                onChange={(e) => setQuestionForm((f) => ({ ...f, questionAr: e.target.value }))}
                rows={2}
                data-testid="input-question-ar"
              />
              <Textarea
                placeholder={lang === "ar" ? "السؤال (إنجليزي)" : "Question (English)"}
                value={questionForm.questionEn}
                onChange={(e) => setQuestionForm((f) => ({ ...f, questionEn: e.target.value }))}
                rows={2}
                data-testid="input-question-en"
              />
              <div className="space-y-2">
                <label className="text-sm font-medium">{t("quiz.options")}</label>
                {questionForm.options.map((opt, i) => (
                  <div key={i} className="grid grid-cols-2 gap-2">
                    <Input
                      placeholder={`${String.fromCharCode(65 + i)} - ${lang === "ar" ? "عربي" : "Arabic"}`}
                      value={opt.textAr}
                      onChange={(e) => {
                        const newOpts = [...questionForm.options];
                        newOpts[i] = { ...newOpts[i], textAr: e.target.value };
                        setQuestionForm((f) => ({ ...f, options: newOpts }));
                      }}
                      data-testid={`input-option-ar-${i}`}
                    />
                    <Input
                      placeholder={`${String.fromCharCode(65 + i)} - ${lang === "ar" ? "إنجليزي" : "English"}`}
                      value={opt.textEn}
                      onChange={(e) => {
                        const newOpts = [...questionForm.options];
                        newOpts[i] = { ...newOpts[i], textEn: e.target.value };
                        setQuestionForm((f) => ({ ...f, options: newOpts }));
                      }}
                      data-testid={`input-option-en-${i}`}
                    />
                  </div>
                ))}
              </div>
              <Select
                value={String(questionForm.correctAnswer)}
                onValueChange={(val) =>
                  setQuestionForm((f) => ({ ...f, correctAnswer: parseInt(val) }))
                }
              >
                <SelectTrigger data-testid="select-correct-answer">
                  <SelectValue placeholder={t("quiz.correctAnswer")} />
                </SelectTrigger>
                <SelectContent>
                  {questionForm.options.map((_, i) => (
                    <SelectItem key={i} value={String(i)}>
                      {String.fromCharCode(65 + i)}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <DialogFooter>
              <Button variant="outline" onClick={() => setQuestionDialogOpen(false)} data-testid="button-cancel-question">
                {t("common.cancel")}
              </Button>
              <Button
                onClick={() => addQuestionMutation.mutate(questionForm)}
                disabled={!questionForm.questionAr || addQuestionMutation.isPending}
                data-testid="button-save-question"
              >
                {t("common.save")}
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>

        <Dialog open={gradeDialogOpen} onOpenChange={setGradeDialogOpen}>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>{t("trainer.gradeProject")}</DialogTitle>
            </DialogHeader>
            <div className="space-y-3">
              <div>
                <label className="text-sm font-medium">{t("trainer.grade")} (0-100)</label>
                <Input
                  type="number"
                  min={0}
                  max={100}
                  value={gradeForm.grade || ""}
                  onChange={(e) =>
                    setGradeForm((f) => ({ ...f, grade: parseInt(e.target.value) || 0 }))
                  }
                  data-testid="input-grade"
                />
              </div>
              <div>
                <label className="text-sm font-medium">{t("trainer.feedback")}</label>
                <Textarea
                  value={gradeForm.feedback}
                  onChange={(e) => setGradeForm((f) => ({ ...f, feedback: e.target.value }))}
                  rows={3}
                  data-testid="input-feedback"
                />
              </div>
            </div>
            <DialogFooter>
              <Button variant="outline" onClick={() => setGradeDialogOpen(false)} data-testid="button-cancel-grade">
                {t("common.cancel")}
              </Button>
              <Button
                onClick={() => {
                  if (selectedProject) {
                    gradeProjectMutation.mutate({
                      id: selectedProject.id,
                      grade: gradeForm.grade,
                      feedback: gradeForm.feedback,
                    });
                  }
                }}
                disabled={gradeProjectMutation.isPending}
                data-testid="button-save-grade"
              >
                {t("common.save")}
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>
      </div>
    );
  }

  return (
    <div className="p-4 sm:p-6 space-y-6 max-w-5xl mx-auto">
      <div className="flex items-center justify-between gap-2 flex-wrap">
        <div>
          <h1 className="text-2xl font-bold" data-testid="text-trainer-title">
            {t("trainer.title")}
          </h1>
          <p className="text-sm text-muted-foreground mt-1">
            {lang === "ar" ? "إنشاء وإدارة الدورات التدريبية" : "Create and manage training courses"}
          </p>
        </div>
        <Button
          onClick={() => setCourseDialogOpen(true)}
          data-testid="button-create-course"
        >
          <Plus className="h-4 w-4" />
          <span className="ms-1.5">{t("trainer.createCourse")}</span>
        </Button>
      </div>

      {isLoading ? (
        <div className="grid sm:grid-cols-2 gap-4">
          {Array.from({ length: 4 }).map((_, i) => (
            <Card key={i}>
              <CardContent className="p-4">
                <Skeleton className="h-20 w-full" />
              </CardContent>
            </Card>
          ))}
        </div>
      ) : courses && courses.length > 0 ? (
        <div className="grid sm:grid-cols-2 gap-4">
          {courses.map((course) => (
            <Card
              key={course.id}
              className="hover-elevate cursor-pointer"
              onClick={() => setSelectedCourse(course)}
              data-testid={`card-trainer-course-${course.id}`}
            >
              <CardContent className="p-4 space-y-3">
                <div className="flex items-start justify-between gap-2">
                  <div className="flex-1 min-w-0 space-y-1">
                    <h3 className="font-semibold text-sm truncate">
                      {lang === "ar" ? course.titleAr : course.titleEn || course.titleAr}
                    </h3>
                    <p className="text-xs text-muted-foreground line-clamp-2">
                      {lang === "ar"
                        ? course.descriptionAr
                        : course.descriptionEn || course.descriptionAr}
                    </p>
                  </div>
                  <Badge
                    variant={course.isPublished ? "default" : "secondary"}
                    data-testid={`badge-publish-status-${course.id}`}
                  >
                    {course.isPublished ? t("common.publish") : t("common.unpublish")}
                  </Badge>
                </div>
                <div className="flex items-center justify-between gap-2">
                  <div className="flex items-center gap-3 text-xs text-muted-foreground flex-wrap">
                    <Badge variant="secondary" className="text-xs">{course.category}</Badge>
                    <span className="flex items-center gap-1">
                      <BookOpen className="h-3 w-3" />
                      {course.duration} {t("courses.hours")}
                    </span>
                  </div>
                  <Button
                    size="sm"
                    variant="ghost"
                    className="text-destructive hover:text-destructive h-7 w-7 p-0 shrink-0"
                    data-testid={`button-delete-course-${course.id}`}
                    onClick={(e) => {
                      e.stopPropagation();
                      if (confirm(lang === "ar" ? "هل أنت متأكد من حذف هذه الدورة وجميع محتوياتها؟" : "Are you sure you want to delete this course and all its content?")) {
                        deleteCourseMutation.mutate(course.id);
                      }
                    }}
                  >
                    <Trash2 className="h-3.5 w-3.5" />
                  </Button>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      ) : (
        <Card>
          <CardContent className="py-16 text-center">
            <GraduationCap className="h-12 w-12 mx-auto mb-4 text-muted-foreground opacity-40" />
            <h3 className="font-medium mb-1">{t("common.noData")}</h3>
            <p className="text-sm text-muted-foreground">
              {lang === "ar" ? "لم يتم إنشاء أي دورة بعد" : "No courses created yet"}
            </p>
          </CardContent>
        </Card>
      )}

      <Dialog open={courseDialogOpen} onOpenChange={setCourseDialogOpen}>
        <DialogContent className="max-w-lg max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>{t("trainer.createCourse")}</DialogTitle>
          </DialogHeader>
          <div className="space-y-3">
            <Input
              placeholder={lang === "ar" ? "عنوان الدورة (عربي)" : "Course Title (Arabic)"}
              value={courseForm.titleAr}
              onChange={(e) => setCourseForm((f) => ({ ...f, titleAr: e.target.value }))}
              data-testid="input-course-title-ar"
            />
            <Input
              placeholder={lang === "ar" ? "عنوان الدورة (إنجليزي)" : "Course Title (English)"}
              value={courseForm.titleEn}
              onChange={(e) => setCourseForm((f) => ({ ...f, titleEn: e.target.value }))}
              data-testid="input-course-title-en"
            />
            <Textarea
              placeholder={lang === "ar" ? "وصف الدورة (عربي)" : "Description (Arabic)"}
              value={courseForm.descriptionAr}
              onChange={(e) => setCourseForm((f) => ({ ...f, descriptionAr: e.target.value }))}
              rows={3}
              data-testid="input-course-desc-ar"
            />
            <Textarea
              placeholder={lang === "ar" ? "وصف الدورة (إنجليزي)" : "Description (English)"}
              value={courseForm.descriptionEn}
              onChange={(e) => setCourseForm((f) => ({ ...f, descriptionEn: e.target.value }))}
              rows={3}
              data-testid="input-course-desc-en"
            />
            <Input
              placeholder={lang === "ar" ? "التصنيف" : "Category"}
              value={courseForm.category}
              onChange={(e) => setCourseForm((f) => ({ ...f, category: e.target.value }))}
              data-testid="input-course-category"
            />
            <Input
              type="number"
              placeholder={t("courses.duration")}
              value={courseForm.duration || ""}
              onChange={(e) =>
                setCourseForm((f) => ({ ...f, duration: parseInt(e.target.value) || 0 }))
              }
              data-testid="input-course-duration"
            />
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setCourseDialogOpen(false)} data-testid="button-cancel-course">
              {t("common.cancel")}
            </Button>
            <Button
              onClick={() => createCourseMutation.mutate(courseForm)}
              disabled={!courseForm.titleAr || !courseForm.category || createCourseMutation.isPending}
              data-testid="button-save-course"
            >
              {t("common.create")}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

client/src/pages/supervisor-dashboard.ts.content:
import { useState } from "react";
import { useI18n } from "@/lib/i18n";
import { useQuery } from "@tanstack/react-query";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Progress } from "@/components/ui/progress";
import { Skeleton } from "@/components/ui/skeleton";
import {
  Table,
  TableHeader,
  TableRow,
  TableHead,
  TableBody,
  TableCell,
} from "@/components/ui/table";
import {
  Users,
  FileText,
  CheckCircle,
  BookOpen,
  BarChart3,
  Clock,
  GraduationCap,
  ScrollText,
} from "lucide-react";
import { Link } from "wouter";
import type { Activity } from "@shared/schema";

interface Stats {
  totalStudents: number;
  totalActivities: number;
  totalApproved: number;
  totalCourses: number;
}

interface HoursByStudent {
  userId: string;
  userName: string;
  major: string;
  totalHours: number;
  approvedActivities: number;
}

interface StudentsByMajor {
  major: string;
  count: number;
}

interface CompletedCourse {
  courseId: string;
  courseName: string;
  completedCount: number;
}

interface ApprovedActivity {
  type: string;
  count: number;
  totalHours: number;
}

interface AuditLogEntry {
  id: string;
  actorUserId: string;
  action: string;
  entityType: string;
  entityId: string | null;
  details: any;
  createdAt: string;
  actorName?: string;
}

type TabType = "overview" | "reports" | "audit";

export default function SupervisorDashboardPage() {
  const { t, lang, dir } = useI18n();
  const [activeTab, setActiveTab] = useState<TabType>("overview");

  const { data: stats, isLoading: statsLoading } = useQuery<Stats>({
    queryKey: ["/api/stats"],
  });

  const { data: allActivities, isLoading: activitiesLoading } = useQuery<Activity[]>({
    queryKey: ["/api/activities/all"],
  });

  const { data: hoursByStudent } = useQuery<HoursByStudent[]>({
    queryKey: ["/api/reports/hours-by-student"],
    enabled: activeTab === "reports",
  });

  const { data: studentsByMajor } = useQuery<StudentsByMajor[]>({
    queryKey: ["/api/reports/students-by-major"],
    enabled: activeTab === "reports",
  });

  const { data: completedCourses } = useQuery<CompletedCourse[]>({
    queryKey: ["/api/reports/completed-courses"],
    enabled: activeTab === "reports",
  });

  const { data: approvedActivities } = useQuery<ApprovedActivity[]>({
    queryKey: ["/api/reports/approved-activities"],
    enabled: activeTab === "reports",
  });

  const { data: auditLogs } = useQuery<AuditLogEntry[]>({
    queryKey: ["/api/audit-logs"],
    enabled: activeTab === "audit",
  });

  const isLoading = statsLoading || activitiesLoading;

  const typeBreakdown: Record<string, number> = {};
  const statusBreakdown: Record<string, number> = {
    approved: 0,
    submitted: 0,
    under_review: 0,
    rejected: 0,
  };

  if (allActivities) {
    allActivities.forEach((a) => {
      typeBreakdown[a.type] = (typeBreakdown[a.type] || 0) + 1;
      if (statusBreakdown[a.status] !== undefined) {
        statusBreakdown[a.status]++;
      }
    });
  }

  const maxTypeCount = Math.max(...Object.values(typeBreakdown), 1);

  const statCards = [
    { key: "totalStudents", label: t("supervisor.totalStudents"), value: stats?.totalStudents ?? 0, icon: Users },
    { key: "totalActivities", label: t("supervisor.totalActivities"), value: stats?.totalActivities ?? 0, icon: FileText },
    { key: "totalApproved", label: t("supervisor.totalApproved"), value: stats?.totalApproved ?? 0, icon: CheckCircle },
    { key: "totalCourses", label: t("supervisor.totalCourses"), value: stats?.totalCourses ?? 0, icon: BookOpen },
  ];

  const pendingCount = (statusBreakdown["submitted"] || 0) + (statusBreakdown["under_review"] || 0);
  const totalStatusCount = (statusBreakdown["approved"] || 0) + pendingCount + (statusBreakdown["rejected"] || 0);

  const tabs: { key: TabType; label: string; icon: any }[] = [
    { key: "overview", label: lang === "ar" ? "نظرة عامة" : "Overview", icon: BarChart3 },
    { key: "reports", label: lang === "ar" ? "التقارير" : "Reports", icon: FileText },
    { key: "audit", label: lang === "ar" ? "سجل التدقيق" : "Audit Log", icon: ScrollText },
  ];

  const actionLabels: Record<string, { ar: string; en: string }> = {
    profile_update: { ar: "تحديث الملف الشخصي", en: "Profile Update" },
    activity_approve: { ar: "اعتماد نشاط", en: "Activity Approved" },
    activity_reject: { ar: "رفض نشاط", en: "Activity Rejected" },
    course_completed: { ar: "إتمام دورة", en: "Course Completed" },
    certificate_issued: { ar: "إصدار شهادة", en: "Certificate Issued" },
  };

  return (
    <div className="p-4 sm:p-6 space-y-6 max-w-7xl mx-auto" dir={dir}>
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3">
        <div className="flex items-center gap-3">
          <BarChart3 className="h-6 w-6" />
          <h1 className="text-2xl font-bold" data-testid="text-supervisor-title">
            {t("supervisor.title")}
          </h1>
        </div>
        <Link href="/review">
          <Button data-testid="link-review">
            <FileText className="h-4 w-4" />
            <span className="ms-1.5">{t("review.title")}</span>
          </Button>
        </Link>
      </div>

      <div className="flex gap-1 border-b">
        {tabs.map((tab) => (
          <button
            key={tab.key}
            onClick={() => setActiveTab(tab.key)}
            className={`flex items-center gap-2 px-4 py-2.5 text-sm font-medium border-b-2 transition-colors ${
              activeTab === tab.key
                ? "border-primary text-primary"
                : "border-transparent text-muted-foreground hover:text-foreground"
            }`}
            data-testid={`tab-${tab.key}`}
          >
            <tab.icon className="h-4 w-4" />
            {tab.label}
          </button>
        ))}
      </div>

      {activeTab === "overview" && (
        <>
          <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
            {isLoading
              ? Array.from({ length: 4 }).map((_, i) => (
                  <Card key={i}>
                    <CardContent className="p-4">
                      <Skeleton className="h-4 w-20 mb-3" />
                      <Skeleton className="h-8 w-16" />
                    </CardContent>
                  </Card>
                ))
              : statCards.map((s) => (
                  <Card key={s.key} data-testid={`card-stat-${s.key}`}>
                    <CardContent className="p-4 space-y-2">
                      <div className="flex items-center gap-2 text-sm text-muted-foreground">
                        <s.icon className="h-4 w-4" />
                        <span>{s.label}</span>
                      </div>
                      <p className="text-3xl font-bold" data-testid={`text-stat-${s.key}`}>
                        {s.value}
                      </p>
                    </CardContent>
                  </Card>
                ))}
          </div>

          <div className="grid lg:grid-cols-2 gap-6">
            <Card>
              <CardHeader className="flex flex-row items-center justify-between gap-1 space-y-0 pb-2">
                <CardTitle className="text-base flex items-center gap-2">
                  <BarChart3 className="h-4 w-4" />
                  {lang === "ar" ? "توزيع الأنشطة حسب النوع" : "Activities by Type"}
                </CardTitle>
              </CardHeader>
              <CardContent>
                {isLoading ? (
                  <div className="space-y-3">
                    {Array.from({ length: 5 }).map((_, i) => (
                      <div key={i} className="space-y-1">
                        <Skeleton className="h-3 w-32" />
                        <Skeleton className="h-5 w-full" />
                      </div>
                    ))}
                  </div>
                ) : (
                  <div className="space-y-3" data-testid="chart-type-breakdown">
                    {Object.entries(typeBreakdown).map(([type, cnt]) => (
                      <div key={type} className="space-y-1">
                        <div className="flex items-center justify-between gap-1 text-sm">
                          <span>{t(`activity.types.${type}`)}</span>
                          <span className="text-muted-foreground tabular-nums">{cnt}</span>
                        </div>
                        <div className="h-5 w-full bg-muted rounded-md overflow-hidden">
                          <div
                            className="h-full bg-primary rounded-md transition-all"
                            style={{ width: `${(cnt / maxTypeCount) * 100}%` }}
                            data-testid={`bar-type-${type}`}
                          />
                        </div>
                      </div>
                    ))}
                    {Object.keys(typeBreakdown).length === 0 && (
                      <p className="text-sm text-muted-foreground text-center py-4">
                        {lang === "ar" ? "لا توجد بيانات" : "No data"}
                      </p>
                    )}
                  </div>
                )}
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="flex flex-row items-center justify-between gap-1 space-y-0 pb-2">
                <CardTitle className="text-base flex items-center gap-2">
                  <CheckCircle className="h-4 w-4" />
                  {lang === "ar" ? "توزيع الأنشطة حسب الحالة" : "Activities by Status"}
                </CardTitle>
              </CardHeader>
              <CardContent>
                {isLoading ? (
                  <div className="space-y-4">
                    {Array.from({ length: 3 }).map((_, i) => (
                      <div key={i} className="space-y-1">
                        <Skeleton className="h-3 w-24" />
                        <Skeleton className="h-2.5 w-full" />
                      </div>
                    ))}
                  </div>
                ) : (
                  <div className="space-y-4" data-testid="chart-status-breakdown">
                    <div className="space-y-1.5">
                      <div className="flex items-center justify-between gap-1 text-sm">
                        <Badge variant="default">{t("status.approved")}</Badge>
                        <span className="text-muted-foreground tabular-nums" data-testid="text-status-approved">
                          {statusBreakdown["approved"]}
                        </span>
                      </div>
                      <Progress value={totalStatusCount ? (statusBreakdown["approved"] / totalStatusCount) * 100 : 0} className="h-2" />
                    </div>
                    <div className="space-y-1.5">
                      <div className="flex items-center justify-between gap-1 text-sm">
                        <Badge variant="secondary">{lang === "ar" ? "قيد المراجعة" : "Pending"}</Badge>
                        <span className="text-muted-foreground tabular-nums" data-testid="text-status-pending">{pendingCount}</span>
                      </div>
                      <Progress value={totalStatusCount ? (pendingCount / totalStatusCount) * 100 : 0} className="h-2" />
                    </div>
                    <div className="space-y-1.5">
                      <div className="flex items-center justify-between gap-1 text-sm">
                        <Badge variant="destructive">{t("status.rejected")}</Badge>
                        <span className="text-muted-foreground tabular-nums" data-testid="text-status-rejected">{statusBreakdown["rejected"]}</span>
                      </div>
                      <Progress value={totalStatusCount ? (statusBreakdown["rejected"] / totalStatusCount) * 100 : 0} className="h-2" />
                    </div>
                    {totalStatusCount === 0 && (
                      <p className="text-sm text-muted-foreground text-center py-4">
                        {lang === "ar" ? "لا توجد بيانات" : "No data"}
                      </p>
                    )}
                  </div>
                )}
              </CardContent>
            </Card>
          </div>
        </>
      )}

      {activeTab === "reports" && (
        <div className="space-y-6">
          <Card>
            <CardHeader>
              <CardTitle className="text-base flex items-center gap-2">
                <Clock className="h-4 w-4" />
                {lang === "ar" ? "تقرير الساعات حسب المتدرب" : "Hours Report by Student"}
              </CardTitle>
            </CardHeader>
            <CardContent>
              {!hoursByStudent ? (
                <div className="space-y-2">
                  {Array.from({ length: 3 }).map((_, i) => <Skeleton key={i} className="h-10 w-full" />)}
                </div>
              ) : hoursByStudent.length === 0 ? (
                <p className="text-sm text-muted-foreground text-center py-4">{lang === "ar" ? "لا توجد بيانات" : "No data"}</p>
              ) : (
                <div className="overflow-x-auto">
                  <Table data-testid="table-hours-by-student">
                    <TableHeader>
                      <TableRow>
                        <TableHead>{lang === "ar" ? "المتدرب" : "Student"}</TableHead>
                        <TableHead>{lang === "ar" ? "التخصص" : "Major"}</TableHead>
                        <TableHead>{lang === "ar" ? "إجمالي الساعات" : "Total Hours"}</TableHead>
                        <TableHead>{lang === "ar" ? "الأنشطة المعتمدة" : "Approved Activities"}</TableHead>
                      </TableRow>
                    </TableHeader>
                    <TableBody>
                      {hoursByStudent.map((row) => (
                        <TableRow key={row.userId}>
                          <TableCell className="font-medium">{row.userName}</TableCell>
                          <TableCell>{row.major}</TableCell>
                          <TableCell className="tabular-nums">{row.totalHours}</TableCell>
                          <TableCell className="tabular-nums">{row.approvedActivities}</TableCell>
                        </TableRow>
                      ))}
                    </TableBody>
                  </Table>
                </div>
              )}
            </CardContent>
          </Card>

          <div className="grid lg:grid-cols-2 gap-6">
            <Card>
              <CardHeader>
                <CardTitle className="text-base flex items-center gap-2">
                  <CheckCircle className="h-4 w-4" />
                  {lang === "ar" ? "تقرير الأنشطة المعتمدة" : "Approved Activities Report"}
                </CardTitle>
              </CardHeader>
              <CardContent>
                {!approvedActivities ? (
                  <div className="space-y-2">
                    {Array.from({ length: 3 }).map((_, i) => <Skeleton key={i} className="h-8 w-full" />)}
                  </div>
                ) : approvedActivities.length === 0 ? (
                  <p className="text-sm text-muted-foreground text-center py-4">{lang === "ar" ? "لا توجد بيانات" : "No data"}</p>
                ) : (
                  <div className="overflow-x-auto">
                    <Table data-testid="table-approved-activities">
                      <TableHeader>
                        <TableRow>
                          <TableHead>{lang === "ar" ? "نوع النشاط" : "Activity Type"}</TableHead>
                          <TableHead>{lang === "ar" ? "العدد" : "Count"}</TableHead>
                          <TableHead>{lang === "ar" ? "إجمالي الساعات" : "Total Hours"}</TableHead>
                        </TableRow>
                      </TableHeader>
                      <TableBody>
                        {approvedActivities.map((row) => (
                          <TableRow key={row.type}>
                            <TableCell>{t(`activity.types.${row.type}`)}</TableCell>
                            <TableCell className="tabular-nums">{row.count}</TableCell>
                            <TableCell className="tabular-nums">{row.totalHours}</TableCell>
                          </TableRow>
                        ))}
                      </TableBody>
                    </Table>
                  </div>
                )}
              </CardContent>
            </Card>

            <Card>
              <CardHeader>
                <CardTitle className="text-base flex items-center gap-2">
                  <Users className="h-4 w-4" />
                  {lang === "ar" ? "المتدربون حسب التخصص" : "Students by Major"}
                </CardTitle>
              </CardHeader>
              <CardContent>
                {!studentsByMajor ? (
                  <div className="space-y-2">
                    {Array.from({ length: 3 }).map((_, i) => <Skeleton key={i} className="h-8 w-full" />)}
                  </div>
                ) : studentsByMajor.length === 0 ? (
                  <p className="text-sm text-muted-foreground text-center py-4">{lang === "ar" ? "لا توجد بيانات" : "No data"}</p>
                ) : (
                  <div className="space-y-3" data-testid="chart-students-by-major">
                    {studentsByMajor.map((row) => {
                      const maxCount = Math.max(...studentsByMajor.map((r) => r.count), 1);
                      return (
                        <div key={row.major} className="space-y-1">
                          <div className="flex items-center justify-between gap-1 text-sm">
                            <span>{row.major}</span>
                            <span className="text-muted-foreground tabular-nums">{row.count}</span>
                          </div>
                          <div className="h-5 w-full bg-muted rounded-md overflow-hidden">
                            <div className="h-full bg-blue-500 rounded-md transition-all" style={{ width: `${(row.count / maxCount) * 100}%` }} />
                          </div>
                        </div>
                      );
                    })}
                  </div>
                )}
              </CardContent>
            </Card>
          </div>

          <Card>
            <CardHeader>
              <CardTitle className="text-base flex items-center gap-2">
                <GraduationCap className="h-4 w-4" />
                {lang === "ar" ? "تقرير الدورات المكتملة" : "Completed Courses Report"}
              </CardTitle>
            </CardHeader>
            <CardContent>
              {!completedCourses ? (
                <div className="space-y-2">
                  {Array.from({ length: 3 }).map((_, i) => <Skeleton key={i} className="h-10 w-full" />)}
                </div>
              ) : completedCourses.length === 0 ? (
                <p className="text-sm text-muted-foreground text-center py-4">{lang === "ar" ? "لا توجد بيانات" : "No data"}</p>
              ) : (
                <div className="overflow-x-auto">
                  <Table data-testid="table-completed-courses">
                    <TableHeader>
                      <TableRow>
                        <TableHead>{lang === "ar" ? "الدورة" : "Course"}</TableHead>
                        <TableHead>{lang === "ar" ? "عدد المتدربين المكتملين" : "Completed Students"}</TableHead>
                      </TableRow>
                    </TableHeader>
                    <TableBody>
                      {completedCourses.map((row) => (
                        <TableRow key={row.courseId}>
                          <TableCell className="font-medium">{row.courseName}</TableCell>
                          <TableCell className="tabular-nums">{row.completedCount}</TableCell>
                        </TableRow>
                      ))}
                    </TableBody>
                  </Table>
                </div>
              )}
            </CardContent>
          </Card>
        </div>
      )}

      {activeTab === "audit" && (
        <Card>
          <CardHeader>
            <CardTitle className="text-base flex items-center gap-2">
              <ScrollText className="h-4 w-4" />
              {lang === "ar" ? "سجل التدقيق" : "Audit Log"}
            </CardTitle>
          </CardHeader>
          <CardContent>
            {!auditLogs ? (
              <div className="space-y-2">
                {Array.from({ length: 5 }).map((_, i) => <Skeleton key={i} className="h-10 w-full" />)}
              </div>
            ) : auditLogs.length === 0 ? (
              <p className="text-sm text-muted-foreground text-center py-8">{lang === "ar" ? "لا توجد سجلات بعد" : "No audit logs yet"}</p>
            ) : (
              <div className="overflow-x-auto">
                <Table data-testid="table-audit-logs">
                  <TableHeader>
                    <TableRow>
                      <TableHead>{lang === "ar" ? "التاريخ" : "Date"}</TableHead>
                      <TableHead>{lang === "ar" ? "المستخدم" : "User"}</TableHead>
                      <TableHead>{lang === "ar" ? "الإجراء" : "Action"}</TableHead>
                      <TableHead>{lang === "ar" ? "النوع" : "Entity"}</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {auditLogs.map((log) => (
                      <TableRow key={log.id}>
                        <TableCell className="text-xs text-muted-foreground whitespace-nowrap">
                          {new Date(log.createdAt).toLocaleString(lang === "ar" ? "ar-SA" : "en-US")}
                        </TableCell>
                        <TableCell className="font-medium">{log.actorName || log.actorUserId}</TableCell>
                        <TableCell>
                          <Badge variant="outline">
                            {actionLabels[log.action]?.[lang] || log.action}
                          </Badge>
                        </TableCell>
                        <TableCell className="text-sm text-muted-foreground">{log.entityType}</TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              </div>
            )}
          </CardContent>
        </Card>
      )}
    </div>
  );
}

