                    : (lang === "ar" ? "حفظ البيانات والمتابعة" : "Save & Continue")}
                </Button>
              </form>
            </Form>
          </CardContent>
        </Card>

        <p className="text-center text-xs text-muted-foreground">
          {lang === "ar"
            ? "بياناتك محمية ولن يتم مشاركتها مع أطراف خارجية"
