                        <span className="text-sm" dir="ltr">{u.email}</span>
                      </TableCell>
                      <TableCell>
                        <Badge variant={roleBadgeVariant(u.role)} className="gap-1">
                          {roleIcon(u.role)}
                          {roleLabel(u.role)}
                        </Badge>
                      </TableCell>
